var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시그마. 잠깐 괜찮니?","JPN":"シグマ。ちょっといいかい？","ENG":"Sigma? Can we talk?","TWN":"西格瑪，能耽誤你一下嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"왜~? 이제 가는 거 아니야?","JPN":"なーに？　もう行くんじゃなかったの？","ENG":"Why? Aren't you leaving now?","TWN":"怎麼了～？爸爸現在就要走了嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠깐은 괜찮아. 마침 시그마에게 해주고 싶은 얘기가 떠올랐거든.","JPN":"まだ大丈夫。シグマに言っておきたいことがあるんだ。","ENG":"I have a bit of time. I remembered something I wanted to tell you.","TWN":"暫時還沒有。正好我想起來有些話要對西格瑪說。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아빠가 떠나고 나면 분명… 우리 딸이 중요한 결정을 해야 하는 순간이 올지도 몰라.","JPN":"パパと離れたら……その先は自分で重要な決断をしていくことになる。","ENG":"After I'm gone... there will come a time when you will have to make an important decision.","TWN":"爸爸離開後，或許會有女兒需要做出重要決定的時候。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아빠가 아닌 시그마가. 무슨 말인지 알겠니?","JPN":"パパではなく、シグマ自身がだ。わかったかい？","ENG":"Not me, but you, Sigma. Do you understand what I'm talking about?","TWN":"不是我，而是西格瑪。明白爸爸的意思嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으음… 잘 모르겠어.","JPN":"うーん……よくわからない。","ENG":"Um... Not really.","TWN":"嗯……不太懂。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어려운 건 아빠가 해주면 안 돼?","JPN":"難しいことはパパがやってほしいな。","ENG":"Can't you do the hard stuff for me, Daddy?","TWN":"困難的事情不能讓爸爸來做決定嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 물론 쉬운 일은 아니겠지.","JPN":"はは、そうだな、もちろん簡単なことではないさ。","ENG":"Ha ha, it's definitely not going to be easy.","TWN":"哈哈，當然不會那麼容易。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 우리 딸이라면 잘 해낼 수 있을 거라고 아빠는 믿어.","JPN":"でも、パパの娘であるシグマなら、きっとできるって信じているぞ。","ENG":"But still, I know you'll do well, Sigma.","TWN":"不過爸爸相信，如果是我女兒的話，一定能做好。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시그마도 아빠를 믿지?","JPN":"シグマもパパを信じてくれるだろう？","ENG":"You believe me, right?","TWN":"西格瑪，你也相信爸爸吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 아빠는 나한테 거짓말 안 하니까!","JPN":"うん！　パパは私に嘘つかないもんね！","ENG":"Of course! You never lie to me, Daddy!","TWN":"嗯！因為爸爸不會騙我！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"잠시만요. 설마 저까지 던지려는 건 아니죠?","JPN":"ちょっと待って、まさか私も投げるつもりじゃないですよね？","ENG":"Wait. You're not going to throw me, are you?","TWN":"等……等等。難道你們也想把我扔出去嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"적은 저쪽이라고요! 저 말고 저 안대 낀 사람을……","JPN":"敵はあっち！　私じゃなくて、あの眼帯をした人間を……","ENG":"The enemy is over there! Don't get me, get that woman with the eyepatch–","TWN":"敵人在那邊！不是我，是那個戴眼罩的傢伙……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"사라졌어?","JPN":"消えた？","ENG":"Where did she go?","TWN":"咦？消失了？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"옷의 원재료인 솔로카오는 침식체 체내의 이터니움을 빨아먹는 생물입니다.","JPN":"服の素材になっているソロカオは侵食体の体内にあるエタニウムを吸って成長する生き物です。","ENG":"Solocao, the material of the clothing, is a creature that feeds on the Eternium inside C.O.s.","TWN":"這個衣服的原材料獨株可可是吸取侵蝕體內永恆之金而生長的生物。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"영양분을 흡수하도록 개량했다 한들, 근원을 생각한다면 일시적인 현상일 수밖에 없죠.","JPN":"栄養素を吸収できるように改良を加えましたが、元々の特性を完全に克服したわけではありません。","ENG":"It has been modified to absorb nutrients, but it is merely a temporary phenomenon considering its origin.","TWN":"即使是改良了吸收的能力，基本上也只是暫時的維持。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"묘기도 끝난 것 같으니 이만 포기하시죠. 치료비는 저희 쪽에서 부담하겠습니다.","JPN":"もうネタも尽きたでしょう。そろそろ諦めませんか？　治療費はわが社が持ちますので。","ENG":"You'd better give up, as it seems like you've run out of tricks. We will cover the medical expenses.","TWN":"既然表演已經結束了，那就放棄吧。治療費用會由我們來承擔。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"병 주고 약주기예요? 기왕이면 상자까지 주면 더 좋을 텐데!","JPN":"飴と鞭ですか？　せっかくなら箱までいただきたいんですけど。","ENG":"How about you provide the chest on top of the medical expenses?","TWN":"喔喔？醫療費用的最上面一條，能把這個箱子也寫上去嗎！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"말장난하는 걸 보니 아직 살만한가 보군요.","JPN":"無駄口を叩くのを見ると、大丈夫なようですね。","ENG":"It seems like you're still energetic enough to be asking ridiculous questions.","TWN":"還在耍嘴皮子，看來還游刃有餘嘛。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"돌아가면 노동청에 신고할 줄 아세요, 이 악덕사업주!","JPN":"向こうに帰ったら、労働省に通報しますからね。この悪徳事業者！","ENG":"I'm going to turn you in to the Ministry of Labor when I get back! You evil boss lady!","TWN":"回去後我會向勞工局舉報你的，你這個惡老闆！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"갑플래닛 평점이 1.24인데 어련하겠습니까? 마음 내키는 대로 하시죠.","JPN":"甲プラネットの評価が星1.24なら、それもやむを得ないですね。お好きにどうぞ。","ENG":"We're already at a score of 1.24 on the job review website. Do whatever you'd like.","TWN":"隨你便吧。反正評分只有1.24。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네, 넷튜브. 넷튜브랑 윙스타에도 올릴 거예요!","JPN":"ね、ネットチューブ。ネットチューブとウィングスターにも書き込みますからね！","ENG":"N-NetTube. I'm going to upload this story to NetTube and Wing-stagram!","TWN":"呃呃！還有網路！我要把影片上傳到網路跟社群平台！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유피…….","JPN":"ユピ……","ENG":"Yuppie...","TWN":"悠菲……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 아빠. 그러다 실수하면 어떡해?","JPN":"パパ、でも選択を間違えたときは、どうすればいいの？","ENG":"But, Daddy. What if I make a mistake?","TWN":"可是爸爸，萬一西格瑪做錯的話怎麼辦？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"친구들에게 민폐 끼치기라도 하면, 나는……","JPN":"みんなに迷惑をかけることだけは、したくないの……","ENG":"If I'm a nuisance to my friends...","TWN":"如果給朋友們添麻煩的話，西格瑪……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"착한 아이가 아닌 거야?","JPN":"そしたら、いい子じゃなくなっちゃうよね？","ENG":"am I not a good girl anymore?","TWN":"就不是個好孩子對嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};